#include <algorithm>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {1, 2, 3};
    // ❌ بدون & — x نسخة، التعديل لا يؤثر على الأصل
    std::for_each(v.begin(), v.end(), [](int x) {
        x *= 10; // يُعدّل النسخة المحلية فقط
    });
    // v لا تزال {1, 2, 3}

    // ✅ مع & — x مرجع للعنصر الأصلي
    std::for_each(v.begin(), v.end(), [](int& x) {
        x *= 10;
    });
    // v الآن {10, 20, 30}
}

