#include <algorithm>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {-3, 5, -1, 7, 0, -8, 2};
    auto mid = std::partition(v.begin(), v.end(), [](int x) { return x > 0; });
    for (int x : v) std::cout << x << ' ';
    // المخرجات (الترتيب النسبي غير مضمون): 5 7 2 -3 -1 0 -8
    std::cout << "\nالموجبة: " << std::distance(v.begin(), mid); // 3
}

#include <algorithm>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {1, 2, 3, 4, 5, 6};
    // نقل الأزواج للنهاية
    auto mid = std::partition(v.begin(), v.end(), [](int x) { return x % 2 != 0; });
    v.erase(mid, v.end());
    for (int x : v) std::cout << x << ' ';
    // المخرجات: 1 3 5 (أو ترتيب آخر للأفراد)
}

