}

#include <numeric>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> a = {1, 2, 3};
    std::vector<int> b = {1, 2, 3};
    // عدّ العناصر المتساوية بدل الجداء الداخلي
    int matches = std::inner_product(a.begin(), a.end(), b.begin(), 0,
        std::plus<>(), std::equal_to<>());
    std::cout << matches; // 3 (كل العناصر متساوية)
}

