#include <iterator>
#include <algorithm>
#include <vector>
#include <iostream>

struct Point { int x, y; };
std::ostream& operator<<(std::ostream& out, const Point& p) {
    return out << "(" << p.x << "," << p.y << ")";
}

int main() {
    std::vector<Point> pts = {{1,2}, {3,4}, {5,6}};
    std::copy(pts.begin(), pts.end(),
        std::ostream_iterator<Point>(std::cout, " "));
    // المخرجات: (1,2) (3,4) (5,6)
}

#include <iterator>
#include <vector>
#include <string>
#include <iostream>

int main() {
    std::vector<std::string> src = {"hello", "world", "cpp"};
    std::vector<std::string> dst;
    dst.reserve(src.size());

    // نقل كل عنصر بدل نسخه — src تصبح فارغة بعد النقل
    std::move_iterator<std::vector<std::string>::iterator>
        move_begin(src.begin());
    std::move_iterator<std::vector<std::string>::iterator>
        move_end(src.end());
    dst.insert(dst.end(), move_begin, move_end);

    for (const auto& s : dst) std::cout << s << ' ';
    // المخرجات: hello world cpp
}

#include <iterator>
#include <vector>
#include <string>
#include <iostream>

int main() {
    std::vector<std::string> src = {"alpha", "beta", "gamma"};
    // make_move_iterator يُنشئ move_iterator من مكرّر عادي
    std::vector<std::string> dst(
        std::make_move_iterator(src.begin()),
        std::make_move_iterator(src.end()));

    for (const auto& s : dst) std::cout << s << ' ';
    // المخرجات: alpha beta gamma
    // src الآن تحتوي سلاسل فارغة (تم نقل محتواها)
}

