#include <iterator>
#include <algorithm>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {1, 2, 3, 4, 5};
    // عكس آخر 3 عناصر فقط
    std::reverse(
        std::make_reverse_iterator(v.end()),
        std::make_reverse_iterator(v.end() - 3));
    for (int x : v) std::cout << x << ' ';
    // المخرجات: 1 2 5 4 3
}

#include <iterator>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {1, 2, 3};

    // الطريقة المباشرة: rbegin()/rend() — أنظم للحاوية كاملة
    for (auto rit = v.rbegin(); rit != v.rend(); ++rit) {
        std::cout << *rit << ' ';
    }
    // المخرجات: 3 2 1

    // make_reverse_iterator: أنسب عند العمل مع مكرّرات جزئية
    auto mid = v.begin() + 1;
    auto rit = std::make_reverse_iterator(mid);
    std::cout << *rit; // 1 (العنصر قبل mid)
}

#include <iterator>
#include <algorithm>
#include <vector>
#include <iostream>

int main() {
    std::vector<int> v = {1, 2, 3, 2, 1};
    // البحث عن آخر 2 في النطاق
    auto rit = std::find(
        std::make_reverse_iterator(v.end()),
        std::make_reverse_iterator(v.begin()), 2);
    if (rit != std::make_reverse_iterator(v.begin())) {
        // base() يُرجع المكرّر العادي
        std::cout << "last 2 at index: " << (rit.base() - v.begin() - 1);
        // المخرجات: 3
    }
}

