std::move_if_noexcept.example:
#include <utility>
#include <iostream>

struct Safe {
    Safe() = default;
    Safe(Safe&&) noexcept { std::cout << "move\n"; }
    Safe(const Safe&) { std::cout << "copy\n"; }
};

int main() {
    Safe s;
    auto&& ref = std::move_if_noexcept(s);
    // إذا كان move noexcept: ref هو rvalue → يستخدم move
    // إذا لم يكن noexcept: ref هو const lvalue → يستخدم copy
}

